import{_ as a,o as i,c as t,ae as r}from"./chunks/framework.BD9pLfSD.js";const u=JSON.parse('{"title":"Branch Plan: Payments (ShadowWire + Privacy Cash)","description":"","frontmatter":{},"headers":[],"relativePath":"docs/plans/branch_payments.md","filePath":"docs/plans/branch_payments.md"}'),o={name:"docs/plans/branch_payments.md"};function l(n,e,s,c,d,h){return i(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="branch-plan-payments-shadowwire-privacy-cash" tabindex="-1">Branch Plan: Payments (ShadowWire + Privacy Cash) <a class="header-anchor" href="#branch-plan-payments-shadowwire-privacy-cash" aria-label="Permalink to &quot;Branch Plan: Payments (ShadowWire + Privacy Cash)&quot;">​</a></h1><h2 id="objective" tabindex="-1">Objective <a class="header-anchor" href="#objective" aria-label="Permalink to &quot;Objective&quot;">​</a></h2><p>Integrate private payment rails for the demo: ShadowWire private transfers and Privacy Cash SDK flows, both callable from the unified SDK surface.</p><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><ul><li>ShadowWire transfer integration (bulletproofs, private amount).</li><li>Privacy Cash SDK integration (private lending/whale wallet flow).</li><li>USD1 usage where supported by the SDKs.</li><li>Payment sequence contract: gateway -&gt; payment -&gt; receipt (SDK-driven).</li></ul><h2 id="out-of-scope" tabindex="-1">Out of Scope <a class="header-anchor" href="#out-of-scope" aria-label="Permalink to &quot;Out of Scope&quot;">​</a></h2><ul><li>On-chain program changes (handled in Core Program branch).</li><li>MCP server integration (handled in SDK/MCP branch).</li><li>Light receipts integration (handled in Infra branch).</li></ul><h2 id="milestones" tabindex="-1">Milestones <a class="header-anchor" href="#milestones" aria-label="Permalink to &quot;Milestones&quot;">​</a></h2><ol><li>ShadowWire transfer works in devnet or in a mock harness.</li><li>Privacy Cash flow works in devnet or in a mock harness.</li><li>Common interface contract documented for SDK consumption (gateway -&gt; payment -&gt; receipt).</li></ol><h2 id="interface-mapping-shadowwire" tabindex="-1">Interface Mapping (ShadowWire) <a class="header-anchor" href="#interface-mapping-shadowwire" aria-label="Permalink to &quot;Interface Mapping (ShadowWire)&quot;">​</a></h2><ul><li>payment_request.amount -&gt; <code>transfer.amount</code> (ShadowWire uses token units, not smallest units).</li><li>payment_request.currency -&gt; <code>transfer.token</code> (USD1 supported).</li><li>payment_request.agent_id -&gt; <code>transfer.sender</code> (wallet address).</li><li>payment_request.vendor -&gt; <code>transfer.recipient</code> (wallet address).</li><li>payment_request.memo_hash -&gt; optional <code>transfer.memo</code> (if SDK supports metadata, else store in receipt_payload.metadata_hash).</li><li>payment_result.tx_sig &lt;- <code>result.tx_signature</code>.</li><li>payment_result.paid_amount &lt;- <code>transfer.amount</code>.</li><li>payment_result.status &lt;- success if <code>tx_signature</code> returned, else failed.</li><li>Wallet signature auth required: SDK must pass <code>wallet.signMessage</code>.</li></ul><h2 id="notes-shadowwire" tabindex="-1">Notes (ShadowWire) <a class="header-anchor" href="#notes-shadowwire" aria-label="Permalink to &quot;Notes (ShadowWire)&quot;">​</a></h2><ul><li>Transfer <code>type</code> choice: <ul><li><code>internal</code> when recipient is a ShadowWire user (amount hidden).</li><li><code>external</code> for non-users (amount visible, sender anonymous).</li></ul></li><li>Proof generation default: backend proofs; client-side proofs optional.</li></ul><h2 id="interface-mapping-privacy-cash" tabindex="-1">Interface Mapping (Privacy Cash) <a class="header-anchor" href="#interface-mapping-privacy-cash" aria-label="Permalink to &quot;Interface Mapping (Privacy Cash)&quot;">​</a></h2><ul><li>payment_request.amount -&gt; <code>deposit.lamports</code> (SOL) or <code>depositSPL.base_units</code>/<code>amount</code> (SPL).</li><li>payment_request.currency -&gt; SPL mint selection (USDC/USDT or USD1 if available).</li><li>payment_request.agent_id -&gt; <code>owner</code> in PrivacyCash client (private key or keypair).</li><li>payment_request.vendor -&gt; <code>withdraw.recipientAddress</code>.</li><li>payment_result.tx_sig &lt;- <code>withdraw</code> response <code>tx</code> (signature string).</li><li>payment_result.paid_amount &lt;- <code>withdraw</code> amount (lamports or base_units).</li><li>payment_result.status &lt;- success if withdraw returns <code>tx</code>.</li><li>Optional metadata from withdraw: <code>isPartial</code>, <code>fee_in_lamports</code> or <code>fee_base_units</code>.</li></ul><h2 id="notes-privacy-cash" tabindex="-1">Notes (Privacy Cash) <a class="header-anchor" href="#notes-privacy-cash" aria-label="Permalink to &quot;Notes (Privacy Cash)&quot;">​</a></h2><ul><li>Flow is 2-step: deposit -&gt; withdraw to recipient.</li><li>For SPL tokens, use <code>depositSPL</code> / <code>withdrawSPL</code> with mint address.</li><li>SDK uses a relayer backend and returns <code>{ tx: signature }</code> for deposits.</li></ul><h2 id="deliverables" tabindex="-1">Deliverables <a class="header-anchor" href="#deliverables" aria-label="Permalink to &quot;Deliverables&quot;">​</a></h2><ul><li>Payment adapter modules with example scripts.</li><li>README snippet for each flow.</li><li>Minimal mock layer if SDKs are unstable.</li></ul><h2 id="dependencies" tabindex="-1">Dependencies <a class="header-anchor" href="#dependencies" aria-label="Permalink to &quot;Dependencies&quot;">​</a></h2><ul><li>ShadowWire SDK + example reference.</li><li>Privacy Cash SDK + example reference.</li></ul><h2 id="risks" tabindex="-1">Risks <a class="header-anchor" href="#risks" aria-label="Permalink to &quot;Risks&quot;">​</a></h2><ul><li>SDK instability or missing localnet support.</li><li>Wallet/key handling friction for demo.</li></ul><h2 id="fallback" tabindex="-1">Fallback <a class="header-anchor" href="#fallback" aria-label="Permalink to &quot;Fallback&quot;">​</a></h2><ul><li>Mock payment execution with signed memo + interface-compatible return.</li></ul><h2 id="breakpoints" tabindex="-1">Breakpoints <a class="header-anchor" href="#breakpoints" aria-label="Permalink to &quot;Breakpoints&quot;">​</a></h2><ul><li>BP1: ShadowWire transfer success path.</li><li>BP2: Privacy Cash flow success path.</li><li>BP3: Unified adapter surface validated by SDK branch.</li></ul>',27)])])}const m=a(o,[["render",l]]);export{u as __pageData,m as default};
